5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Libraries
9	------------------------------------------------------------------------------
10	library ieee;
11		use ieee.std_logic_1164.all;
12		use ieee.numeric_std.all;
13		
14	library work;
15		use work.mem_test_pkg.all;
16		use work.psi_common_math_pkg.all;
17		
18	------------------------------------------------------------------------------
19	-- Entity
20	------------------------------------------------------------------------------	
21	-- $$ testcases=simple_tf,max_transact,axi_hs,split,internals,highlat$$
22	-- $$ processes=user_cmd,user_data,user_resp,axi $$
23	-- $$ tbpkg=work.psi_tb_txt_util,work.psi_tb_compare_pkg,work.psi_tb_activity_pkg $$
24	entity mem_test is
25		generic (
26			AxiAddrWidth_g				: natural range 12 to 64	:= 32;						-- $$ constant=32 $$
27			AxiDataWidth_g				: natural range 16 to 1024	:= 32						-- $$ constant=16 $$
28		);
29		port  (
30			-- Control Signals
31			Clk				: in 	std_logic;													-- $$ type=clk; freq=100e6 $$
32			Rst_n			: in 	std_logic;													-- $$ type=rst; clk=Clk; lowactive=true $$
33			
34			-- Register bank interface
35			Reg_Rd			: in	rd_t;
36			Reg_RData		: out	rdata_t;
37			Reg_Wr			: in	wr_t;
38			Reg_WData		: in	wdata_t;
39			
40			-- AXI Master Interface
41			CmdWr_Addr		: out 	std_logic_vector(AxiAddrWidth_g-1 downto 0);
42			CmdWr_Size		: out 	std_logic_vector(AxiAddrWidth_g-1 downto 0);  
43			CmdWr_LowLat	: out 	std_logic;	
44			CmdWr_Vld		: out 	std_logic;	
45			CmdWr_Rdy		: in 	std_logic;			
46			CmdRd_Addr		: out 	std_logic_vector(AxiAddrWidth_g-1 downto 0);	
47			CmdRd_Size		: out 	std_logic_vector(AxiAddrWidth_g-1 downto 0); 
48			CmdRd_LowLat	: out 	std_logic;				
49			CmdRd_Vld		: out 	std_logic;				
50			CmdRd_Rdy		: in 	std_logic;							
51			WrDat_Data		: out 	std_logic_vector(AxiDataWidth_g-1 downto 0);
52			WrDat_Be		: out 	std_logic_vector(AxiDataWidth_g/8-1 downto 0);
53			WrDat_Vld		: out 	std_logic;												
54			WrDat_Rdy		: in 	std_logic;												
55			RdDat_Data		: in 	std_logic_vector(AxiDataWidth_g-1 downto 0);		
56			RdDat_Vld		: in 	std_logic;												
57			RdDat_Rdy		: out 	std_logic;												
58			Wr_Done			: in 	std_logic;												
59			Wr_Error		: in 	std_logic;												
60			Rd_Done			: in 	std_logic;												
61			Rd_Error		: in 	std_logic				
62		);
63	end entity;
64	
65	------------------------------------------------------------------------------
66	-- Architecture section
67	------------------------------------------------------------------------------
68	architecture rtl of mem_test is 
69		------------------------------------------------------------------------------
70		-- Types
71		------------------------------------------------------------------------------	
72		type Fsm_t is (Idle_s, WrCmd_s, Write_s, RdCmd_s, Read_s, AxiError_s, IntError_s);
73		
74		------------------------------------------------------------------------------
75		-- Functions
76		------------------------------------------------------------------------------
77		function FsmToInt(	fsm : in Fsm_t) return integer is
78		begin
79			case fsm is
80				when Idle_s  	=> return C_STATUS_IDLE;
81				when Write_s |
82					 WrCmd_s 	=> return C_STATUS_WRITING;
83				when Read_s |
84					 RdCmd_s	=> return C_STATUS_READING;
85				when AxiError_s	=> return C_STATUS_AXIERR;
86				when IntError_s	=> return C_STATUS_INTERR;
87				when others		=> return C_STATUS_UNKNOWN;
88			end case;
89		end function;
90		
91		------------------------------------------------------------------------------
92		-- Two Process Record
93		------------------------------------------------------------------------------		
94		type two_process_r is record	
95			Fsm 			: Fsm_t;
96			Errors			: unsigned(31 downto 0);
97			FirstErrAddr	: unsigned(AxiAddrWidth_g-1 downto 0);
98			Pattern			: std_logic_vector(AxiDataWidth_g-1 downto 0);
99			PatternCnt		: unsigned(AxiAddrWidth_g-1 downto 0);
100			CmdWr_Addr		: unsigned(AxiAddrWidth_g-1 downto 0);
101			CmdWr_Vld		: std_logic;
102			CmdWr_Size		: unsigned(AxiAddrWidth_g-1 downto 0);
103			WrDat_Vld		: std_logic;
104			CmdRd_Addr		: unsigned(AxiAddrWidth_g-1 downto 0);
105			CmdRd_Vld		: std_logic;
106			CmdRd_Size		: unsigned(AxiAddrWidth_g-1 downto 0);
107			RdDat_Rdy		: std_logic;
108			ContRunning		: std_logic;
109			FirstErrFound	: std_logic;
110			ContIter		: unsigned(31 downto 0);
111		end record;
112		signal r, r_next : two_process_r;
113		
114		------------------------------------------------------------------------------
115		-- Other Signals
116		------------------------------------------------------------------------------
117		signal Rst 		: std_logic;
118	begin
119		------------------------------------------------------------------------------
120		-- Constant Assignments
121		------------------------------------------------------------------------------	
122		Rst <= not Rst_n;
123	
124		------------------------------------------------------------------------------
125		-- Combinatorial Process
126		------------------------------------------------------------------------------	
127		p_comb : process(	r, Reg_Rd, Reg_Wr, Reg_WData, Wr_Error, Rd_Error,
128							CmdWr_Rdy, WrDat_Rdy, CmdRd_Rdy, RdDat_Vld, RdDat_Data)
129			variable v 					: two_process_r;
130			variable RegStart_v			: std_logic;
131			variable RegStop_v			: std_logic;
132			variable RegReset_v			: std_logic;
133			variable RegSize_v			: unsigned(63 downto 0);
134			variable RegAddr_v			: unsigned(63 downto 0);
135			variable RegMode_v			: unsigned(RNG_MODE);
136			variable RegPatternSel_v	: unsigned(RNG_PATTERN_SEL);
137			variable FirstErrAddr64_v	: unsigned(63 downto 0);
138			variable InitPattern_v		: boolean;
139			variable UpdatePattern_v	: boolean;
140			variable AddrBeats_v		: unsigned(AxiAddrWidth_g-1-log2(AxiDataWidth_g/8) downto 0);
141		begin
142			-- *** Keep two process variables stable ***
143			v := r;
144			
145			-- *** Registers ***
146			-- START
147			RegStart_v 	:= Reg_WData(REG_START)(C_START_START) and Reg_Wr(REG_START);
148			
149			-- STOP
150			RegStop_v 	:= Reg_WData(REG_STOP)(C_STOP_STOP) and Reg_Wr(REG_STOP);
151			
152			-- SIZE
153			RegSize_v 	:= unsigned(Reg_WData(REG_SIZE_HI)) & unsigned(Reg_WData(REG_SIZE_LO));
154			Reg_RData(REG_SIZE_LO) <= std_logic_vector(RegSize_v(31 downto 0));
155			Reg_RData(REG_SIZE_HI) <= std_logic_vector(RegSize_v(63 downto 32));
156			
157			-- ADDR
158			RegAddr_v 	:= unsigned(Reg_WData(REG_ADDR_HI)) & unsigned(Reg_WData(REG_ADDR_LO));
159			Reg_RData(REG_ADDR_LO) <= std_logic_vector(RegAddr_v(31 downto 0));
160			Reg_RData(REG_ADDR_HI) <= std_logic_vector(RegAddr_v(63 downto 32));		
161			
162			-- MODE
163			RegMode_v	:= unsigned(Reg_WData(REG_MODE)(RNG_MODE));
164			Reg_RData(REG_MODE) <= (others => '0');
165			Reg_RData(REG_MODE)(RNG_MODE) <= std_logic_vector(RegMode_v);
166			
167			-- PATTERN SEL
168			RegPatternSel_v	:= unsigned(Reg_WData(REG_PATTERN_SEL)(RNG_PATTERN_SEL));
169			Reg_RData(REG_PATTERN_SEL) <= (others => '0');
170			Reg_RData(REG_PATTERN_SEL)(RNG_PATTERN_SEL) <= std_logic_vector(RegPatternSel_v);		
171			
172			-- STATUS
173			Reg_RData(REG_STATUS) <= (others => '0');
174			Reg_RData(REG_STATUS)(RNG_STATUS) <= std_logic_vector(to_unsigned(FsmToInt(r.Fsm), RNG_STATUS'high+1));
175			
176			-- ERRORS
177			Reg_RData(REG_ERRORS) <= std_logic_vector(r.Errors);
178			
179			-- FIRST ERROR ADDR
180			FirstErrAddr64_v := resize(r.FirstErrAddr, 64);
181			Reg_RData(REG_FERR_ADDR_LO) <= std_logic_vector(FirstErrAddr64_v(31 downto 0));
182			Reg_RData(REG_FERR_ADDR_HI) <= std_logic_vector(FirstErrAddr64_v(63 downto 32));
183			
184			-- ITERATIONS
185			Reg_RData(REG_ITER)	<= std_logic_vector(r.ContIter);
186			
187			-- *** Detect continuous running ***
188			if RegStart_v = '1' then
189				if RegMode_v = C_MODE_CONTINUOUS then
190					v.ContRunning := '1';
191				else
192					v.ContRunning := '0';
193				end if;
194			end if;
195			if RegStop_v = '1' then
196				v.ContRunning := '0';
197			end if;
198			
199			-- *** Main Fsm ***
200			v.CmdWr_Vld := '0';
201			v.WrDat_Vld := '0';
202			v.CmdRd_Vld := '0';
203			v.RdDat_Rdy	:= '0';
204			InitPattern_v := false;
205			UpdatePattern_v := false;
206			case r.Fsm is
207				
208				-- Idle
209				when Idle_s =>
210					-- Start run and clear statistics
211					if RegStart_v = '1' then
212						if RegMode_v = C_MODE_READONLY then
213							v.Fsm			:= RdCmd_s;
214						else
215							v.Fsm			:= WrCmd_s;
216						end if;
217						v.FirstErrAddr 	:= (others => '0');
218						v.Errors		:= (others => '0');
219						v.FirstErrFound := '0';
220						v.ContIter		:= (others => '0');
221					end if;
222					
223				-- Write command
224				when WrCmd_s =>
225					v.CmdWr_Addr 	:= RegAddr_v(v.CmdWr_Addr'range);
226					v.CmdWr_Addr(log2(AxiDataWidth_g/8)-1 downto 0)	:= (others => '0');	-- Do not write unused bits
227					v.CmdWr_Size	:= shift_right(RegSize_v(v.CmdRd_Size'left downto 0), log2(AxiDataWidth_g/8));
228					v.CmdWr_Vld		:= '1';
229					v.PatternCnt	:= (others => '0');
230					InitPattern_v	:= true;
231					if (r.CmdWr_Vld = '1') and (CmdWr_Rdy = '1') then
232						v.Fsm 			:= Write_s;
233						v.CmdWr_Vld		:= '0';
234					end if;			
235				
236				-- Write Date
237				when Write_s =>
238					v.WrDat_Vld	:= '1';
239					if (r.WrDat_Vld = '1' ) and (WrDat_Rdy = '1') then
240						-- Last word sent
241						if r.PatternCnt = r.CmdWr_Size-1 then
242							if RegMode_v = C_MODE_WRITEONLY then
243								v.Fsm		:= Idle_s;
244							else
245								v.Fsm		:= RdCmd_s;
246							end if;
247							v.WrDat_Vld	:= '0';					
248						-- Otherwise
249						else
250							v.PatternCnt	:= r.PatternCnt+1;
251							UpdatePattern_v := true;
252						end if;
253					end if;
254						
255				-- Read command
256				when RdCmd_s =>
257					v.CmdRd_Addr 	:= RegAddr_v(v.CmdRd_Addr'range);
258					v.CmdRd_Addr(log2(AxiDataWidth_g/8)-1 downto 0)	:= (others => '0');	-- Do not write unused bits
259					v.CmdRd_Size	:= shift_right(RegSize_v(v.CmdRd_Size'left downto 0), log2(AxiDataWidth_g/8));
260					v.CmdRd_Vld		:= '1';
261					v.PatternCnt	:= (others => '0');
262					InitPattern_v	:= true;
263					if (r.CmdRd_Vld = '1') and (CmdRd_Rdy = '1') then
264						v.Fsm 			:= Read_s;
265						v.CmdRd_Vld		:= '0';
266					end if;			
267	
268				-- Read Data
269				when Read_s =>
270					v.RdDat_Rdy	:= '1';
271					if (r.RdDat_Rdy = '1') and (RdDat_Vld = '1') then
272						-- Last word read
273						if r.PatternCnt = r.CmdRd_Size-1 then
274							v.ContIter	:= r.ContIter+1;
275							if r.ContRunning = '1' then	
276								v.Fsm 		:= WrCmd_s;
277							else
278								v.Fsm := Idle_s;
279							end if;
280							v.RdDat_Rdy	:= '0';					
281						-- otherwise
282						else
283							v.PatternCnt	:= r.PatternCnt+1;
284							UpdatePattern_v := true;
285						end if;
286						
287						-- Pattern check
288						if RdDat_Data /= r.Pattern then
289							v.Errors := r.Errors + 1;
290							v.FirstErrFound := '1';
291							if r.FirstErrFound = '0' then
292								AddrBeats_v := resize(r.PatternCnt, AddrBeats_v'length) + RegAddr_v(AxiAddrWidth_g-1 downto log2(AxiDataWidth_g/8));
293								v.FirstErrAddr	:= shift_left(to_unsigned(0, log2(AxiDataWidth_g/8)) & AddrBeats_v, log2(AxiDataWidth_g/8));
294							end if;
295						end if;	
296					end if;
297	
298				-- AXI ERROR
299				when AxiError_s =>
300					-- Non recoverable!
301					null;
302					
303				-- Internal ERROR
304				when IntError_s =>
305					-- Non recoverable!
306					null;
307						
308			end case;
309			
310			-- *** Shared Code ***
311			-- Initialize Pattern
312			if InitPattern_v then
313				case to_integer(RegPatternSel_v) is
314					when C_PATTERN_SEL_COUNT =>	
315						v.Pattern		:= (others => '0');
316					when C_PATTERN_SEL_WALK1 => 
317						v.Pattern 		:= (others => '0');
318						v.Pattern(0)	:= '1';
319					when C_PATTERN_SEL_OWNADD =>
320						v.Pattern		:= std_logic_vector(resize(RegAddr_v, v.Pattern'length));
321					when C_PATTERN_SEL_PRBN =>
322						v.Pattern 				:= (others => '0');
323						v.Pattern(15 downto 0)	:= X"6D3F";
324					when others =>
325						v.Fsm := IntError_s;
326				end case;
327			end if;
328			
329			-- Update Pattern
330			if UpdatePattern_v then
331				case to_integer(RegPatternSel_v) is
332					when C_PATTERN_SEL_COUNT =>	
333						v.Pattern		:= std_logic_vector(unsigned(r.Pattern) + 1);
334					when C_PATTERN_SEL_WALK1 => 
335						v.Pattern(0)	:= r.Pattern(r.Pattern'high);
336						v.Pattern(v.Pattern'high downto 1) := r.Pattern(r.Pattern'high-1 downto 0);
337					when C_PATTERN_SEL_OWNADD =>
338						v.Pattern		:= std_logic_vector(unsigned(r.Pattern) + AxiDataWidth_g/8);
339					when C_PATTERN_SEL_PRBN =>
340						v.Pattern(0)	:= r.Pattern(15) xor r.Pattern(13) xor r.Pattern(12) xor r.Pattern(10);
341						v.Pattern(v.Pattern'high downto 1) := r.Pattern(r.Pattern'high-1 downto 0);
342					when others =>
343						v.Fsm := IntError_s;
344				end case;
345			end if;
346				
347				
348				
349			-- *** Error States cannot be left!
350			if r.Fsm = IntError_s then	
351				v.Fsm	:= IntError_s;
352			end if;
353			if r.Fsm = AxiError_s then
354				v.Fsm 	:= AxiError_s;
355			end if;
356			if (Wr_Error = '1') or (Rd_Error = '1') then
357				v.Fsm 	:= AxiError_s;
358			end if;	
359			
360			-- *** Update Signal ***
361			r_next <= v;
362		end process;
363		
364		CmdWr_Addr 		<= std_logic_vector(r.CmdWr_Addr);
365		CmdWr_Vld		<= r.CmdWr_Vld;
366		CmdWr_Size		<= std_logic_vector(r.CmdWr_Size);	
367		WrDat_Data		<= std_logic_vector(r.Pattern);
368		WrDat_Be		<= (others => '1');
369		WrDat_Vld		<= r.WrDat_Vld;
370		CmdRd_Addr 		<= std_logic_vector(r.CmdRd_Addr);
371		CmdRd_Vld		<= r.CmdRd_Vld;
372		CmdRd_Size		<= std_logic_vector(r.CmdRd_Size);	
373		RdDat_Rdy		<= r.RdDat_Rdy;
374		CmdWr_LowLat	<= '0';
375		CmdRd_LowLat	<= '0';
376	
377		------------------------------------------------------------------------------
378		-- Registered Process
379		------------------------------------------------------------------------------
380		p_reg : process(clk)
381		begin
382			if rising_edge(Clk) then
383				r <= r_next;
384				if Rst = '1' then
385					r.Fsm			<= Idle_s;
386					r.CmdWr_Vld		<= '0';
387					r.WrDat_Vld		<= '0';
388					r.CmdRd_Vld		<= '0';
389					r.RdDat_Rdy		<= '0';
390					r.ContRunning	<= '0';
391				end if;
392			end if;
393		end process;	
394	end architecture;
395

