------------------------------------------------------------------------------
-- Libraries
------------------------------------------------------------------------------
library ieee;
	use ieee.std_logic_1164.all;
	use ieee.numeric_std.all;

library work;
	use work.psi_common_array_pkg.all;	

------------------------------------------------------------------------------
-- Package Header
------------------------------------------------------------------------------
package mem_test_pkg is

	-- Register General
	constant USER_SLV_NUM_REG      : integer := 32; -- only powers of 2 are allowed
	subtype rd_t 	is	std_logic_vector(USER_SLV_NUM_REG-1 downto  0);
	subtype rdata_t	is	t_aslv32(0 to USER_SLV_NUM_REG-1);
	subtype wr_t	is	std_logic_vector(USER_SLV_NUM_REG-1 downto  0);
	subtype wdata_t	is 	t_aslv32(0 to USER_SLV_NUM_REG-1);

	-- Register Definition
	constant REG_START				: integer	:= 0;				-- 0x00
	constant C_START_START			: natural	:= 0;

	constant REG_STOP				: integer	:= 1;				-- 0x04
	constant C_STOP_STOP			: natural	:= 0;	

	constant REG_MODE				: integer	:= 3;				-- 0x0C
	subtype RNG_MODE				is natural range 2 downto 0;
	constant C_MODE_SINGLE			: integer := 0;
	constant C_MODE_CONTINUOUS		: integer := 1;
	constant C_MODE_WRITEONLY		: integer := 2;
	constant C_MODE_READONLY		: integer := 3;

	constant REG_SIZE_LO			: integer	:= 4;				-- 0x10
	constant REG_SIZE_HI			: integer	:= 5;				-- 0x14

	constant REG_ADDR_LO			: integer	:= 6;				-- 0x18
	constant REG_ADDR_HI			: integer	:= 7;				-- 0x1C

	constant REG_PATTERN_SEL		: integer	:= 8;				-- 0x20
	subtype RNG_PATTERN_SEL			is natural range 2 downto 0;	
	constant C_PATTERN_SEL_COUNT	: integer := 0;
	constant C_PATTERN_SEL_WALK1	: integer := 1;
	constant C_PATTERN_SEL_OWNADD	: integer := 2;
	constant C_PATTERN_SEL_PRBN		: integer := 3;

	constant REG_STATUS				: integer	:= 9;				-- 0x24
	subtype RNG_STATUS				is natural range 2 downto 0;
	constant C_STATUS_IDLE			: integer := 0;
	constant C_STATUS_WRITING		: integer := 1;
	constant C_STATUS_READING		: integer := 2;
	constant C_STATUS_AXIERR		: integer := 3;		
	constant C_STATUS_INTERR		: integer := 6;
	constant C_STATUS_UNKNOWN		: integer := 7;

	constant REG_ERRORS				: integer := 10;				-- 0x28

	constant REG_FERR_ADDR_LO		: integer := 11;				-- 0x2C
	constant REG_FERR_ADDR_HI		: integer := 12;				-- 0x30
	constant REG_ITER				: integer := 13;				-- 0x34




end package;

/*############################################################################
#  Copyright (c) 2019 by Paul Scherrer Institute, Switzerland
#  All rights reserved.
#  Authors: Oliver Bruendler
############################################################################*/

#pragma once

#ifdef __cplusplus
extern "C" {
#endif

//*******************************************************************************
// Includes
//*******************************************************************************
#include <stdint.h>
#include <stdbool.h>

//*******************************************************************************
// Constants
//*******************************************************************************

#define MEM_TEST_START_OFFS					0x00
#define MEM_TEST_STOP_OFFS					0x04
#define MEM_TEST_MODE_OFFS					0x0C
#define MEM_TEST_SIZE_LO_OFFS				0x10
#define MEM_TEST_SIZE_HI_OFFS				0x14
#define MEM_TEST_ADDR_LO_OFFS				0x18
#define MEM_TEST_ADDR_HI_OFFS				0x1C
#define MEM_TEST_PATTERN_OFFS				0x20
#define MEM_TEST_STATUS_OFFS				0x24
#define MEM_TEST_ERRORS_OFFS				0x28
#define MEM_TEST_FIRSTERR_LO_OFFS			0x2C
#define MEM_TEST_FIRSTERR_HI_OFFS			0x30
#define MEM_TEST_ITER_OFFS					0x34

//*******************************************************************************
// Types
//*******************************************************************************
typedef enum {RANDOM, IMMEDIATE, SEARCH} strategy;

typedef enum {
	MemTest_Mode_Single = 0,
	MemTest_Mode_Continuous = 1,
	MemTest_Mode_WriteOnly = 2,
	MemTest_Mode_ReadOnly = 3
} MemTest_Mode;

typedef enum {
	MemTest_Pattern_Count = 0,
	MemTest_Pattern_Walk1 = 1,
	MemTest_Pattern_OwnAddr = 2,
	MemTest_Pattern_Prbn = 3
} MemTest_Pattern;

typedef enum {
	MemTest_Status_Idle = 0,
	MemTest_Status_Writing = 1,
	MemTest_Status_Reading = 2,
	MemTest_Status_AxiErr = 3,
	MemTest_Status_IntErr = 6,
	MemTest_Status_Unknown = 7
} MemTest_Status;


//*******************************************************************************
// Functions
//*******************************************************************************

//Start Memory Test
void MemTest_Start(const uint32_t baseAddr);

//Stop Memory Test (only required in continuous mode)
void MemTest_Stop(const uint32_t baseAddr);

//Set memory test mode (only allowed if stopped)
void MemTest_SetMode(	const uint32_t baseAddr,
						const MemTest_Mode mode);

//Set memory test pattern (only allowed if stopped)
void MemTest_SetPattern(	const uint32_t baseAddr,
							const MemTest_Pattern pattern);

//Set memory range to test (only allowed if stopped)
void MemTest_SetRange(	const uint32_t baseAddr,
						const uint64_t startAddr,
						const uint64_t size);

//Get Memory Tester Status
MemTest_Status MemTest_GetStatus(const uint32_t baseAddr);

//Get Error Counter (cleared on Start())
uint32_t MemTest_GetErrors(const uint32_t baseAddr);

//Get Iteration Counter (cleared on Start())
uint32_t MemTest_GetIterations(const uint32_t baseAddr);

//Get Address of first error
uint64_t MemTest_GetFirstErrorAddr(const uint32_t baseAddr);

#ifdef __cplusplus
}
#endif

