42		Xil_Out32(baseAddr+MEM_TEST_SIZE_HI_OFFS, (uint32_t)(size >> 32));
43		Xil_Out32(baseAddr+MEM_TEST_ADDR_LO_OFFS, (uint32_t)startAddr);
44		Xil_Out32(baseAddr+MEM_TEST_ADDR_HI_OFFS, (uint32_t)(startAddr >> 32));							
45	}
