47	//Get Memory Tester Status
48	MemTest_Status MemTest_GetStatus(const uint32_t baseAddr)
49	{
50		return (MemTest_Status)Xil_In32(baseAddr+MEM_TEST_STATUS_OFFS);
51	}
52	
53	//Get Error Counter (cleared on Start())
54	uint32_t MemTest_GetErrors(const uint32_t baseAddr)
55	{
56		return Xil_In32(baseAddr+MEM_TEST_ERRORS_OFFS);
57	}
58	
59	//Get Iteration Counter (cleared on Start())
60	uint32_t MemTest_GetIterations(const uint32_t baseAddr)
61	{
62		return Xil_In32(baseAddr+MEM_TEST_ITER_OFFS);
63	}
64	
65	//Get Address of first error
66	uint64_t MemTest_GetFirstErrorAddr(const uint32_t baseAddr)
67	{
68		const uint64_t addrHigh = Xil_In32(baseAddr+MEM_TEST_FIRSTERR_HI_OFFS);
69		const uint64_t addrLow  = Xil_In32(baseAddr+MEM_TEST_FIRSTERR_LO_OFFS);
70		return (addrHigh << 32) | addrLow;	
71	}
