91		-------------------------------------------------------------------------	
92		procedure axi_expect_wd_walk1(	Beats		: in 	natural;
93										DataStart	: in	natural;
94										variable DataEnd		: out	natural;
95										signal ms	: in	axi_ms_r;
96										signal sm	: out	axi_sm_r;
97										signal aclk	: in	std_logic) is
98			variable DataStdlv_v	: std_logic_vector(ms.wdata'range);									
99		begin
100			sm.wready <= '1';
101			DataStdlv_v := std_logic_vector(to_unsigned(DataStart, DataStdlv_v'length));
102			for beat in 1 to Beats loop	
103				wait until rising_edge(aclk) and ms.wvalid = '1';
104				-- last transfer
105				assert signed(ms.wstrb) = -1 report "###ERROR###: wrong WSTRB" severity error;
106				if beat = Beats then
107					assert ms.wlast = '1' report "###ERROR###: WLAST not asserted at end of burst transfer" severity error;
108				elsif beat = 1 then
109					assert ms.wlast = '0' report "###ERROR###: WLAST asserted at beginning of burst transfer" severity error;
110				else
111					assert ms.wlast = '0' report "###ERROR###: WLAST asserted in the middle of burst transfer" severity error;
112				end if;
113				-- Apply Data
114				assert ms.wdata = DataStdlv_v report "###ERROR###: wrong WDATA during butst transfer" severity error;
115				DataStdlv_v := DataStdlv_v(DataStdlv_v'high-1 downto 0) & DataStdlv_v(DataStdlv_v'high);	
116				-- Low cycles if required
117				if not (beat = Beats) then
118					sm.wready <= '1';
119				end if;			
120			end loop;
121			sm.wready <= '0';
122			DataEnd := to_integer(signed(DataStdlv_v));
123		end procedure;	
124		
125		procedure axi_apply_rresp_walk1 (	Beats		: in 	natural;
126											DataStart	: in	natural;
127											variable DataEnd		: out	natural;
128											Response	: in 	std_logic_vector(1 downto 0);
129											signal ms	: in	axi_ms_r;
130											signal sm	: out	axi_sm_r;
131											signal aclk	: in	std_logic) is
132			variable DataStdlv_v	: std_logic_vector(ms.wdata'range);
133		begin		
134			sm.rvalid 	<= '1';	
135			sm.rlast 	<= '0';
136			DataStdlv_v := std_logic_vector(to_unsigned(DataStart, DataStdlv_v'length));
137			sm.rresp <= Response;
138			for beat in 1 to Beats loop	
139				-- last transfer
140				if beat = Beats then
141					sm.rlast <= '1';
142				end if;
143				-- Apply Data
144				sm.rdata <= DataStdlv_v;			
145				wait until rising_edge(aclk) and ms.rready = '1';
146				DataStdlv_v := DataStdlv_v(DataStdlv_v'high-1 downto 0) & DataStdlv_v(DataStdlv_v'high);
147				-- Low cycles if required
148				if not (beat = Beats) then
149					sm.rvalid <= '1';
150				end if;
151			end loop;
152			axi_slave_init(sm);
153			DataEnd := to_integer(signed(DataStdlv_v));
154		end procedure;		
