246		
247		-------------------------------------------------------------------------
248		-- Clock
249		-------------------------------------------------------------------------
250		p_aclk : process
251		begin
252			aclk <= '0';
253			while TbRunning loop
254				wait for 0.5*ClockPeriodAxi_c;
255				aclk <= '1';
256				wait for 0.5*ClockPeriodAxi_c;
257				aclk <= '0';
258			end loop;
259			wait;
260		end process;
261		
262		-------------------------------------------------------------------------
263		-- TB Control
264		-------------------------------------------------------------------------
265		p_control : process
266			variable Readback_v	: integer;
267			variable ReadbackSlv_v : std_logic_vector(31 downto 0);
268		begin
269			-- Reset
270			aresetn <= '0';
271			wait for 1 us;
272			wait until rising_edge(aclk);
273			aresetn <= '1';
274			wait for 1 us;
275			wait until rising_edge(aclk);
276			
277			-- *** Start Own Address Pattern from 0xA8 to 0x1A7, success ***
278			print(">> Start Own Address Pattern from 0xA8 to 0x1A7, success");
279			axi_single_write(REG_MODE*4, 		C_MODE_SINGLE, 				s_axi_ms, s_axi_sm, aclk);
280			axi_single_write(REG_SIZE_LO*4, 	16#100#, 					s_axi_ms, s_axi_sm, aclk);
281			axi_single_write(REG_PATTERN_SEL*4, C_PATTERN_SEL_OWNADD, 		s_axi_ms, s_axi_sm, aclk);
282			axi_single_write(REG_ADDR_LO*4, 	16#A8#, 					s_axi_ms, s_axi_sm, aclk);
283			axi_single_write(REG_START*4, 		1, 							s_axi_ms, s_axi_sm, aclk);
284			SetupDone <= 0;
285			wait until AxiDone = 0;
286			wait until rising_edge(aclk);
287			axi_single_expect(REG_STATUS*4,		 C_STATUS_IDLE, 		s_axi_ms, s_axi_sm, aclk, "Status not idle 0"); 	
288			axi_single_expect(REG_ERRORS*4,		 0, 					s_axi_ms, s_axi_sm, aclk, "Unexpected Errors 0");
289	
290			-- *** Start Own Address Pattern from 0xA8 to 0x1A7, errors ***		
291			print(">> Start Own Address Pattern from 0xA8 to 0x1A7, errors");
292			axi_single_write(REG_MODE*4, 		C_MODE_SINGLE, 				s_axi_ms, s_axi_sm, aclk);
293			axi_single_write(REG_SIZE_LO*4, 	16#100#, 					s_axi_ms, s_axi_sm, aclk);
294			axi_single_write(REG_PATTERN_SEL*4, C_PATTERN_SEL_OWNADD, 		s_axi_ms, s_axi_sm, aclk);
295			axi_single_write(REG_ADDR_LO*4, 	16#A8#, 					s_axi_ms, s_axi_sm, aclk);
296			axi_single_write(REG_START*4, 		1, 							s_axi_ms, s_axi_sm, aclk);
297			SetupDone <= 1;
298			-- Check if status is updated
299			Readback_v := 0;
300			while Readback_v /= C_STATUS_WRITING loop
301				axi_single_read(REG_STATUS*4, Readback_v, s_axi_ms, s_axi_sm, aclk);
302			end loop;
303			Readback_v := 0;
304			while Readback_v /= C_STATUS_READING loop
305				axi_single_read(REG_STATUS*4, Readback_v, s_axi_ms, s_axi_sm, aclk);
306			end loop;	
307			-- Check result
308			wait until AxiDone = 1;
309			wait until rising_edge(aclk);
310			axi_single_expect(REG_STATUS*4,		 C_STATUS_IDLE, 		s_axi_ms, s_axi_sm, aclk, "Status not idle 1"); 	
311			axi_single_expect(REG_ERRORS*4,		 15, 					s_axi_ms, s_axi_sm, aclk, "Errors not found 1");
312			axi_single_expect(REG_FERR_ADDR_LO*4,16#EC#, 				s_axi_ms, s_axi_sm, aclk, "Error addr lo wrong 1");
313			axi_single_expect(REG_FERR_ADDR_HI*4,0, 					s_axi_ms, s_axi_sm, aclk, "Error addr hi wrong 1");
314	
315			-- *** Continuous ***
316			print(">> Continuous");
317			axi_single_write(REG_MODE*4, 		C_MODE_CONTINUOUS, 			s_axi_ms, s_axi_sm, aclk);
318			axi_single_write(REG_SIZE_LO*4, 	16#100#, 					s_axi_ms, s_axi_sm, aclk);
319			axi_single_write(REG_PATTERN_SEL*4, C_PATTERN_SEL_OWNADD, 		s_axi_ms, s_axi_sm, aclk);
320			axi_single_write(REG_ADDR_LO*4, 	16#A8#, 					s_axi_ms, s_axi_sm, aclk);
321			axi_single_write(REG_START*4, 		1, 							s_axi_ms, s_axi_sm, aclk);
322			SetupDone <= 2;
323			-- Check if iteration counter
324			Readback_v := 0;
325			while Readback_v /= 2 loop
326				axi_single_read(REG_ITER*4, Readback_v, s_axi_ms, s_axi_sm, aclk);
327			end loop;
328			-- Stop continuous running during 3rd iteration
329			axi_single_write(REG_STOP*4, 		1, 							s_axi_ms, s_axi_sm, aclk);
330			wait until AxiDone = 2;
331			wait until rising_edge(aclk);
332			axi_single_expect(REG_STATUS*4,		 C_STATUS_IDLE, 		s_axi_ms, s_axi_sm, aclk, "Status not idle 2"); 	
333			axi_single_expect(REG_ERRORS*4,		 15*3, 					s_axi_ms, s_axi_sm, aclk, "Errors not found 2");
334			axi_single_expect(REG_ITER*4,		 3, 					s_axi_ms, s_axi_sm, aclk, "Wrong Iteration counter 2");
335			
336			-- *** Start Counter Pattern from 0xA8 to 0x1A7, success ***
337			print(">> Start Counter Pattern from 0xA8 to 0x1A7, success");
338			axi_single_write(REG_MODE*4, 		C_MODE_SINGLE, 				s_axi_ms, s_axi_sm, aclk);
339			axi_single_write(REG_SIZE_LO*4, 	16#100#, 					s_axi_ms, s_axi_sm, aclk);
340			axi_single_write(REG_PATTERN_SEL*4, C_PATTERN_SEL_COUNT, 		s_axi_ms, s_axi_sm, aclk);
341			axi_single_write(REG_ADDR_LO*4, 	16#A8#, 					s_axi_ms, s_axi_sm, aclk);
342			axi_single_write(REG_START*4, 		1, 							s_axi_ms, s_axi_sm, aclk);
343			SetupDone <= 3;
344			wait until AxiDone = 3;
345			wait until rising_edge(aclk);
346			axi_single_expect(REG_STATUS*4,		 C_STATUS_IDLE, 		s_axi_ms, s_axi_sm, aclk, "Status not idle 3"); 	
347			axi_single_expect(REG_ERRORS*4,		 0, 					s_axi_ms, s_axi_sm, aclk, "Unexpected Errors 3");
348			
349			-- *** Walking 1 Pattern from 0x000 to 0x200, errors ***		
350			print(">> Walking 1 Pattern from 0x000 to 0x200, errors");
351			axi_single_write(REG_MODE*4, 		C_MODE_SINGLE, 				s_axi_ms, s_axi_sm, aclk);
352			axi_single_write(REG_SIZE_LO*4, 	16#200#, 					s_axi_ms, s_axi_sm, aclk);
353			axi_single_write(REG_PATTERN_SEL*4, C_PATTERN_SEL_WALK1, 		s_axi_ms, s_axi_sm, aclk);
354			axi_single_write(REG_ADDR_LO*4, 	16#000#, 					s_axi_ms, s_axi_sm, aclk);
355			axi_single_write(REG_START*4, 		1, 							s_axi_ms, s_axi_sm, aclk);
356			SetupDone <= 4;
357			-- Check result
358			wait until AxiDone = 4;
359			wait until rising_edge(aclk);
360			axi_single_expect(REG_STATUS*4,		 C_STATUS_IDLE, 		s_axi_ms, s_axi_sm, aclk, "Status not idle 4"); 	
361			axi_single_expect(REG_ERRORS*4,		 16, 					s_axi_ms, s_axi_sm, aclk, "Errors not found 4");
362			axi_single_expect(REG_FERR_ADDR_LO*4,16#1C0#, 				s_axi_ms, s_axi_sm, aclk, "Error addr lo wrong 4");
363			axi_single_expect(REG_FERR_ADDR_HI*4, 0, 					s_axi_ms, s_axi_sm, aclk, "Error addr hi wrong 4");		
364			
365			-- *** Write Only ***
366			print(">> Write Only");
367			axi_single_write(REG_MODE*4, 		C_MODE_WRITEONLY, 			s_axi_ms, s_axi_sm, aclk);
368			axi_single_write(REG_SIZE_LO*4, 	16#100#, 					s_axi_ms, s_axi_sm, aclk);
369			axi_single_write(REG_PATTERN_SEL*4, C_PATTERN_SEL_OWNADD, 		s_axi_ms, s_axi_sm, aclk);
370			axi_single_write(REG_ADDR_LO*4, 	16#A8#, 					s_axi_ms, s_axi_sm, aclk);
371			axi_single_write(REG_START*4, 		1, 							s_axi_ms, s_axi_sm, aclk);
372			SetupDone <= 5;
373			Readback_v := -1;
374			while Readback_v /= C_STATUS_IDLE loop
375				axi_single_read(REG_STATUS*4, Readback_v, s_axi_ms, s_axi_sm, aclk);
376				assert Readback_v /= C_STATUS_READING report "###ERROR###: read operation during write-only" severity error;
377			end loop;	
378			wait until rising_edge(aclk);
379			axi_single_expect(REG_STATUS*4,		 C_STATUS_IDLE, 		s_axi_ms, s_axi_sm, aclk, "Status not idle 5"); 	
380			axi_single_expect(REG_ERRORS*4,		 0, 					s_axi_ms, s_axi_sm, aclk, "Unexpected Errors 5");		
381			
382			-- *** Read Only ***
383			print(">> Read Only");
384			axi_single_write(REG_MODE*4, 		C_MODE_READONLY, 			s_axi_ms, s_axi_sm, aclk);
385			axi_single_write(REG_SIZE_LO*4, 	16#100#, 					s_axi_ms, s_axi_sm, aclk);
386			axi_single_write(REG_PATTERN_SEL*4, C_PATTERN_SEL_OWNADD, 		s_axi_ms, s_axi_sm, aclk);
387			axi_single_write(REG_ADDR_LO*4, 	16#A8#, 					s_axi_ms, s_axi_sm, aclk);
388			axi_single_write(REG_START*4, 		1, 							s_axi_ms, s_axi_sm, aclk);
389			SetupDone <= 6;
390			Readback_v := -1;
391			while Readback_v /= C_STATUS_IDLE loop
392				axi_single_read(REG_STATUS*4, Readback_v, s_axi_ms, s_axi_sm, aclk);
393				assert Readback_v /= C_STATUS_WRITING report "###ERROR###: write operation during read-only" severity error;
394			end loop;	
395			wait until rising_edge(aclk);
396			axi_single_expect(REG_STATUS*4,		 C_STATUS_IDLE, 		s_axi_ms, s_axi_sm, aclk, "Status not idle 6"); 	
397			axi_single_expect(REG_ERRORS*4,		 0, 					s_axi_ms, s_axi_sm, aclk, "Unexpected Errors 6");			
398			
399			-- TB done
400			TbRunning <= false;
401			wait;
402		end process;
403		
404		-------------------------------------------------------------------------
405		-- AXI Emulation
406		-------------------------------------------------------------------------
407		p_axi : process
408			variable Addr_v : integer	:= 0;
409			variable Cnt_v : integer  := 0;
410			variable Incr_v : integer;
411		begin	
412			-- *** Start Own Address Pattern from 0xA8 to 0x1A7, success ***		
413			wait until SetupDone = 0;
414			wait until rising_edge(aclk);
415			Addr_v := 16#A8#;
416			while Addr_v < 16#1A8# loop
417				axi_expect_aw(	Addr_v, AxSIZE_4_c, 16-1, xBURST_INCR_c, m_axi_ms, m_axi_sm, aclk);
418				axi_expect_wd_burst(16, Addr_v, 4, "1111", "1111", m_axi_ms, m_axi_sm, aclk);
419				axi_apply_bresp(xRESP_OKAY_c, m_axi_ms, m_axi_sm, aclk);
420				Addr_v := Addr_v + 16*4;
421			end loop;
422			Addr_v := 16#A8#;
423			while Addr_v < 16#1A8# loop
424				axi_expect_ar(	Addr_v, AxSIZE_4_c, 16-1, xBURST_INCR_c, m_axi_ms, m_axi_sm, aclk);
425				axi_apply_rresp_burst(	16, Addr_v, 4, xRESP_OKAY_c, m_axi_ms, m_axi_sm, aclk);
426				Addr_v := Addr_v + 16*4;
427			end loop;	
428			AxiDone <= 0;		
429			
430			-- *** Start Own Address Pattern from 0xA8 to 0x1A7, errors ***
431			wait until SetupDone = 1;
432			wait until rising_edge(aclk);
433			Addr_v := 16#A8#;
434			while Addr_v < 16#1A8# loop
435				axi_expect_aw(	Addr_v, AxSIZE_4_c, 16-1, xBURST_INCR_c, m_axi_ms, m_axi_sm, aclk);
436				axi_expect_wd_burst(16, Addr_v, 4, "1111", "1111", m_axi_ms, m_axi_sm, aclk);
437				axi_apply_bresp(xRESP_OKAY_c, m_axi_ms, m_axi_sm, aclk);
438				Addr_v := Addr_v + 16*4;
439			end loop;
440			Addr_v := 16#A8#;
441			while Addr_v < 16#1A8# loop
442				-- For the address block starting at 16#A8#+16*4 , use a wrong increment to produce 15 errors (first error at 0xEC)
443				if Addr_v = 16#E8# then
444					Incr_v := 1;
445				else
446					Incr_v := 4;
447				end if;
448				axi_expect_ar(	Addr_v, AxSIZE_4_c, 16-1, xBURST_INCR_c, m_axi_ms, m_axi_sm, aclk);
449				axi_apply_rresp_burst(	16, Addr_v, Incr_v, xRESP_OKAY_c, m_axi_ms, m_axi_sm, aclk);
450				Addr_v := Addr_v + 16*4;
451			end loop;	
452			AxiDone <= 1;	
453	
454			-- *** Continuous *** (same as above but 3 times)
455			wait until SetupDone = 2;
456			wait until rising_edge(aclk);
457			for i in 0 to 2 loop
458				Addr_v := 16#A8#;
459				while Addr_v < 16#1A8# loop
460					axi_expect_aw(	Addr_v, AxSIZE_4_c, 16-1, xBURST_INCR_c, m_axi_ms, m_axi_sm, aclk);
461					axi_expect_wd_burst(16, Addr_v, 4, "1111", "1111", m_axi_ms, m_axi_sm, aclk);
462					axi_apply_bresp(xRESP_OKAY_c, m_axi_ms, m_axi_sm, aclk);
463					Addr_v := Addr_v + 16*4;
464				end loop;
465				Addr_v := 16#A8#;
466				while Addr_v < 16#1A8# loop
467					-- For the address block starting at 16#A8#+16*4 , use a wrong increment to produce 15 errors (first error at 0xEC)
468					if Addr_v = 16#E8# then
469						Incr_v := 1;
470					else
471						Incr_v := 4;
472					end if;
473					axi_expect_ar(	Addr_v, AxSIZE_4_c, 16-1, xBURST_INCR_c, m_axi_ms, m_axi_sm, aclk);
474					axi_apply_rresp_burst(	16, Addr_v, Incr_v, xRESP_OKAY_c, m_axi_ms, m_axi_sm, aclk);
475					Addr_v := Addr_v + 16*4;
476				end loop;	
477			end loop;
478			AxiDone <= 2;	
479			
480			-- *** Start Counter Pattern from 0xA8 to 0x1A7, success ***
481			wait until SetupDone = 3;
482			wait until rising_edge(aclk);
483			Addr_v := 16#A8#;
484			Cnt_v := 0;
485			while Addr_v < 16#1A8# loop
486				axi_expect_aw(	Addr_v, AxSIZE_4_c, 16-1, xBURST_INCR_c, m_axi_ms, m_axi_sm, aclk);
487				axi_expect_wd_burst(16, Cnt_v, 1, "1111", "1111", m_axi_ms, m_axi_sm, aclk);
488				axi_apply_bresp(xRESP_OKAY_c, m_axi_ms, m_axi_sm, aclk);
489				Addr_v := Addr_v + 16*4;
490				Cnt_v := Cnt_v + 16;
491			end loop;
492			Addr_v := 16#A8#;
493			Cnt_v := 0;
494			while Addr_v < 16#1A8# loop
495				axi_expect_ar(	Addr_v, AxSIZE_4_c, 16-1, xBURST_INCR_c, m_axi_ms, m_axi_sm, aclk);
496				axi_apply_rresp_burst(	16, Cnt_v, 1, xRESP_OKAY_c, m_axi_ms, m_axi_sm, aclk);
497				Addr_v := Addr_v + 16*4;
498				Cnt_v := Cnt_v + 16;
499			end loop;	
500			AxiDone <= 3;			
501		
502			-- *** Walking 1 Pattern from 0x000 to 0x200, errors ***
503			wait until SetupDone = 4;
504			wait until rising_edge(aclk);
505			Addr_v := 16#000#;
506			Cnt_v := 1;
507			while Addr_v < 16#1FC# loop
508				axi_expect_aw(	Addr_v, AxSIZE_4_c, 16-1, xBURST_INCR_c, m_axi_ms, m_axi_sm, aclk);
509				axi_expect_wd_walk1(16, Cnt_v, Cnt_v, m_axi_ms, m_axi_sm, aclk);
510				axi_apply_bresp(xRESP_OKAY_c, m_axi_ms, m_axi_sm, aclk);
511				Addr_v := Addr_v + 16*4;
512			end loop;
513			Addr_v := 16#000#;
514			Cnt_v := 1;
515			while Addr_v < 16#1FC# loop
516				if Addr_v = 16#1C0# then
517					Cnt_v := Cnt_v + 1;
518				end if;
519				axi_expect_ar(	Addr_v, AxSIZE_4_c, 16-1, xBURST_INCR_c, m_axi_ms, m_axi_sm, aclk);
520				axi_apply_rresp_walk1(	16, Cnt_v, Cnt_v, xRESP_OKAY_c, m_axi_ms, m_axi_sm, aclk);
521				Addr_v := Addr_v + 16*4;
522			end loop;	
523			AxiDone <= 4;	
524			
525			-- *** Write Only ***		
526			wait until SetupDone = 5;
527			wait until rising_edge(aclk);
528			Addr_v := 16#A8#;
529			while Addr_v < 16#1A8# loop
530				axi_expect_aw(	Addr_v, AxSIZE_4_c, 16-1, xBURST_INCR_c, m_axi_ms, m_axi_sm, aclk);
531				axi_expect_wd_burst(16, Addr_v, 4, "1111", "1111", m_axi_ms, m_axi_sm, aclk);
532				axi_apply_bresp(xRESP_OKAY_c, m_axi_ms, m_axi_sm, aclk);
533				Addr_v := Addr_v + 16*4;
534			end loop;	
535			AxiDone <= 5;	
536			
537			-- *** Read Only  ***		
538			wait until SetupDone = 6;
539			wait until rising_edge(aclk);
540			Addr_v := 16#A8#;
541			while Addr_v < 16#1A8# loop
542				axi_expect_ar(	Addr_v, AxSIZE_4_c, 16-1, xBURST_INCR_c, m_axi_ms, m_axi_sm, aclk);
543				axi_apply_rresp_burst(	16, Addr_v, 4, xRESP_OKAY_c, m_axi_ms, m_axi_sm, aclk);
544				Addr_v := Addr_v + 16*4;
545			end loop;	
546			AxiDone <= 6;			
547			
548			wait;
549		end process;	
550		
551	
552	end sim;
553

