7	proc init { cellpath otherInfo } {
8	
9	   set cell_handle [get_bd_cells $cellpath]
10	   set all_busif [get_bd_intf_pins $cellpath/*]
11	   set axi_standard_param_list [list ID_WIDTH]
12	   set full_sbusif_list [list  S00_AXI ]
13	
14	   foreach busif $all_busif {
15	      if { [string equal -nocase [get_property MODE $busif] "slave"] == 1 } {
16	         set busif_param_list [list]
17	         set busif_name [get_property NAME $busif]
18	         if { [lsearch -exact -nocase $full_sbusif_list $busif_name ] == -1 } {
19	             continue
20	         }
21	         foreach tparam $axi_standard_param_list {
22	            lappend busif_param_list "C_${busif_name}_${tparam}"
23	         }
24	         bd::mark_propagate_only $cell_handle $busif_param_list
25	      }
26	   }
27	}
