30	proc pre_propagate {cellpath otherInfo } {
31	
32	   set cell_handle [get_bd_cells $cellpath]
33	   set all_busif [get_bd_intf_pins $cellpath/*]
34	   set axi_standard_param_list [list ID_WIDTH]
35	
36	   foreach busif $all_busif {
37	      if { [string equal -nocase [get_property CONFIG.PROTOCOL $busif] "AXI4"] != 1 } {
38	         continue
39	      }
40	      if { [string equal -nocase [get_property MODE $busif] "master"] != 1 } {
41	         continue
42	      }
43	
44	      set busif_name [get_property NAME $busif]
45	      foreach tparam $axi_standard_param_list {
46	         set busif_param_name "C_${busif_name}_${tparam}"
47	
48	         set val_on_cell_intf_pin [get_property CONFIG.${tparam} $busif]
49	         set val_on_cell [get_property CONFIG.${busif_param_name} $cell_handle]
50	
51	         if { [string equal -nocase $val_on_cell_intf_pin $val_on_cell] != 1 } {
52	            if { $val_on_cell != "" } {
53	               set_property CONFIG.${tparam} $val_on_cell $busif
54	            }
55	         }
56	      }
57	   }
58	}
