60	
61	proc propagate {cellpath otherInfo } {
62	
63	   set cell_handle [get_bd_cells $cellpath]
64	   set all_busif [get_bd_intf_pins $cellpath/*]
65	   set axi_standard_param_list [list ID_WIDTH]
66	
67	   foreach busif $all_busif {
68	      if { [string equal -nocase [get_property CONFIG.PROTOCOL $busif] "AXI4"] != 1 } {
69	         continue
70	      }
71	      if { [string equal -nocase [get_property MODE $busif] "slave"] != 1 } {
72	         continue
73	      }
74	
75	      set busif_name [get_property NAME $busif]
76	      foreach tparam $axi_standard_param_list {
77	         set busif_param_name "C_${busif_name}_${tparam}"
78	
79	         set val_on_cell_intf_pin [get_property CONFIG.${tparam} $busif]
80	         set val_on_cell [get_property CONFIG.${busif_param_name} $cell_handle]
81	
